import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What are all the costs of owning a home?", a: "Common homeownership costs include mortgage principal and interest, property tax, insurance, HOA fees, maintenance, utilities, and repairs." },
  { q: "What is the 1% rule in real estate?", a: "The 1% rule is a rental property shortcut suggesting monthly rent should be about 1% of purchase price, though real deals require deeper analysis." },
  { q: "How do you calculate property ROI?", a: "Property ROI usually compares annual profit or equity gain to cash invested, after accounting for expenses and financing." },
  { q: "What is a good cap rate for rental property?", a: "A good cap rate depends on location, property type, risk, financing, and growth prospects. Higher cap rates often come with higher risk." },
  { q: "How does property tax work?", a: "Property tax is usually based on assessed value multiplied by a local tax rate, and it can change over time." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

function payment(principal: number, apr: number, years: number) {
  const months = years * 12;
  const r = apr / 100 / 12;
  return r === 0 ? principal / months : principal * r / (1 - Math.pow(1 + r, -months));
}

export default function RealEstateCalculator() {
  useCurrencyVersion();
  const [price, setPrice] = useState(350000);
  const [down, setDown] = useState(70000);
  const [rate, setRate] = useState(6.5);
  const [term, setTerm] = useState(30);
  const [taxRate, setTaxRate] = useState(1.2);
  const [insurance, setInsurance] = useState(1200);
  const [hoa, setHoa] = useState(150);
  const [maintenance, setMaintenance] = useState(1);
  const [rent, setRent] = useState(2200);

  const result = useMemo(() => {
    const loan = Math.max(0, price - down);
    const mortgage = payment(loan, rate, term);
    const taxMonthly = price * taxRate / 100 / 12;
    const insuranceMonthly = insurance / 12;
    const maintenanceMonthly = price * maintenance / 100 / 12;
    const monthly = mortgage + taxMonthly + insuranceMonthly + hoa + maintenanceMonthly;
    return { loan, mortgage, taxMonthly, insuranceMonthly, maintenanceMonthly, monthly, annual: monthly * 12, rentDifference: monthly - rent };
  }, [price, down, rate, term, taxRate, insurance, hoa, maintenance, rent]);

  const components = [
    ["Mortgage P+I", result.mortgage],
    ["Property Tax", result.taxMonthly],
    ["Insurance", result.insuranceMonthly],
    ["HOA", hoa],
    ["Maintenance", result.maintenanceMonthly],
    ["Total Cost", result.monthly],
  ];

  return (
    <>
      <SEOHead title="Free Real Estate Calculator Online - Calculate True Cost of Homeownership Instantly | CalcHive" description="Free online real estate calculator. Calculate total monthly homeownership costs including mortgage, taxes, insurance and maintenance for any property instantly. 100% free, no signup required." canonical="/real-estate-calculator" keywords="free real estate calculator, cost of homeownership calculator free, property cost calculator free online, home buying cost calculator free, real estate investment calculator free" category="Financial Calculators" breadcrumbName="Free Real Estate Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Real Estate Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate the true monthly and annual cost of owning a home, including hidden costs.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            {[["Purchase price", price, setPrice], ["Down payment", down, setDown], ["Mortgage rate (%)", rate, setRate], ["Term years", term, setTerm], ["Property tax rate (%)", taxRate, setTaxRate], ["Annual insurance", insurance, setInsurance], ["Monthly HOA", hoa, setHoa], ["Maintenance (%/yr)", maintenance, setMaintenance], ["Comparable rent", rent, setRent]].map(([label, value, setter]) => <div key={String(label)}><label className="text-sm font-semibold text-foreground block mb-2">{String(label)}</label><input type="number" value={Number(value)} onChange={(e) => (setter as (v: number) => void)(Number(e.target.value))} className={inputClass} /></div>)}
          </div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Total Monthly Housing Cost</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.monthly)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Mortgage P+I</p><p className="text-lg font-extrabold text-foreground">{money(result.mortgage)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Annual ownership cost</p><p className="text-lg font-extrabold text-foreground">{money(result.annual)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Own vs rent monthly</p><p className="text-lg font-extrabold text-foreground">{money(result.rentDifference)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate the True Cost of Homeownership for Free</h2><p className="text-muted-foreground leading-relaxed">Add mortgage principal and interest, property tax, insurance, HOA, and maintenance to estimate the real monthly cost.</p>
          <h2 className="text-2xl font-bold text-foreground">What Are All the Hidden Costs of Buying a Home</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">True Cost of Homeownership - $350,000 Home at 6.5%</caption><thead className="bg-muted/60"><tr>{["Cost Component", "Monthly", "Annual", "5 Years", "10 Years"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{components.map(([name, monthly]) => <tr key={String(name)}><td className="py-2.5 px-3 font-semibold">{String(name)}</td><td className="py-2.5 px-3">{money(Number(monthly))}</td><td className="py-2.5 px-3">{money(Number(monthly) * 12)}</td><td className="py-2.5 px-3">{money(Number(monthly) * 60)}</td><td className="py-2.5 px-3">{money(Number(monthly) * 120)}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free Property Cost Calculator for Home Buyers</h2><p className="text-muted-foreground leading-relaxed">Use this real estate calculator before buying so you can compare mortgage payment, rent, and ownership expenses clearly.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/real-estate-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


